"use client";

import React, { useCallback, useMemo, useState } from "react";
import {
  LiveblocksProvider,
  RoomProvider,
  useSelf,
  useStorage,
  useMutation,
  ClientSideSuspense,
} from "@liveblocks/react/suspense";
import {
  LiveObject,
  LiveList,
  LiveMap,
} from "@liveblocks/client";

const ROOM_ID = `poll-room-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID || "local"}`;

function PollInner() {
  const role = useSelf((me) => me.info.role);
  const myId = useSelf((me) => me.id);

  const question = useStorage((storage) => storage.poll.question);
  const options = useStorage((storage) => storage.poll.options);
  const votes = useStorage((storage) => storage.votes);

  const [newOptionLabel, setNewOptionLabel] = useState("");

  // Compute tallies
  const { totalVotes, optionCounts } = useMemo(() => {
    const counts: Record<string, number> = {};
    let total = 0;
    for (const [, optionId] of Object.entries(votes as Record<string, string>)) {
      counts[optionId] = (counts[optionId] || 0) + 1;
      total++;
    }
    return { totalVotes: total, optionCounts: counts };
  }, [votes]);

  // Set question (owner only)
  const setQuestion = useMutation(
    ({ storage }, value: string) => {
      storage.get("poll").set("question", value);
    },
    []
  );

  // Add option (owner only)
  const addOption = useMutation(
    ({ storage }, label: string) => {
      const id = crypto.randomUUID();
      storage.get("poll").get("options").push(new LiveObject({ id, label }));
    },
    []
  );

  // Remove option (owner only)
  const removeOption = useMutation(
    ({ storage }, optionId: string) => {
      const opts = storage.get("poll").get("options");
      const index = opts.toArray().findIndex((o) => o.get("id") === optionId);
      if (index !== -1) {
        opts.delete(index);
      }
    },
    []
  );

  // Vote
  const vote = useMutation(
    ({ storage }, optionId: string) => {
      storage.get("votes").set(myId, optionId);
    },
    [myId]
  );

  const handleAddOption = useCallback(() => {
    const trimmed = newOptionLabel.trim();
    if (trimmed) {
      addOption(trimmed);
      setNewOptionLabel("");
    }
  }, [newOptionLabel, addOption]);

  const isOwner = role === "owner";

  return (
    <div style={{ padding: 24, fontFamily: "system-ui", maxWidth: 600 }}>
      <h1>Liveblocks Collaborative Poll</h1>

      {/* Question input */}
      {isOwner ? (
        <div style={{ marginBottom: 16 }}>
          <label style={{ display: "block", marginBottom: 4, fontWeight: "bold" }}>
            Question:
          </label>
          <input
            data-testid="question-input"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            placeholder="Enter poll question..."
            style={{ width: "100%", padding: 8, fontSize: 16 }}
          />
        </div>
      ) : (
        <div style={{ marginBottom: 16 }}>
          <label style={{ display: "block", marginBottom: 4, fontWeight: "bold" }}>
            Question:
          </label>
          <input
            data-testid="question-input"
            value={question}
            readOnly
            disabled
            style={{ width: "100%", padding: 8, fontSize: 16, opacity: 0.6 }}
          />
        </div>
      )}

      {/* Add option form (owner only) */}
      {isOwner && (
        <div style={{ marginBottom: 16, display: "flex", gap: 8 }}>
          <input
            data-testid="new-option-input"
            value={newOptionLabel}
            onChange={(e) => setNewOptionLabel(e.target.value)}
            placeholder="New option..."
            style={{ flex: 1, padding: 8, fontSize: 14 }}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleAddOption();
            }}
          />
          <button
            data-testid="add-option-btn"
            onClick={handleAddOption}
            style={{ padding: "8px 16px", fontSize: 14 }}
          >
            Add option
          </button>
        </div>
      )}

      {/* Options list */}
      <div style={{ marginBottom: 16 }}>
        {options.map((option, index) => {
          const id = option.id;
          const label = option.label;
          const count = optionCounts[id] || 0;
          const percentage =
            totalVotes === 0 ? 0 : Math.round((count / totalVotes) * 100);
          const myVote = (votes as Record<string, string>)?.[myId];

          return (
            <div
              key={id}
              style={{
                marginBottom: 12,
                padding: 12,
                border: "1px solid #ddd",
                borderRadius: 8,
              }}
            >
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  marginBottom: 4,
                }}
              >
                <span data-testid={`label-${id}`} style={{ fontWeight: "bold" }}>
                  {label}
                </span>
                <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                  <button
                    data-testid={`vote-${id}`}
                    onClick={() => vote(id)}
                    style={{
                      padding: "4px 12px",
                      fontSize: 13,
                      background: myVote === id ? "#4CAF50" : "#2196F3",
                      color: "white",
                      border: "none",
                      borderRadius: 4,
                      cursor: "pointer",
                    }}
                  >
                    {myVote === id ? "✓ Voted" : "Vote"}
                  </button>
                  {isOwner && (
                    <button
                      data-testid={`remove-${id}`}
                      onClick={() => removeOption(id)}
                      style={{
                        padding: "4px 8px",
                        fontSize: 13,
                        background: "#f44336",
                        color: "white",
                        border: "none",
                        borderRadius: 4,
                        cursor: "pointer",
                      }}
                    >
                      Remove
                    </button>
                  )}
                </div>
              </div>
              <div
                style={{
                  background: "#e0e0e0",
                  borderRadius: 4,
                  overflow: "hidden",
                  height: 24,
                  position: "relative",
                }}
              >
                <div
                  style={{
                    width: `${percentage}%`,
                    background: "#4CAF50",
                    height: "100%",
                    transition: "width 0.3s ease",
                  }}
                />
                <span
                  data-testid={`bar-${id}`}
                  style={{
                    position: "absolute",
                    top: 0,
                    left: 8,
                    lineHeight: "24px",
                    fontSize: 13,
                    fontWeight: "bold",
                  }}
                >
                  {percentage}%
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {/* Total votes */}
      <div data-testid="total-votes" style={{ fontWeight: "bold" }}>
        Total votes: {totalVotes}
      </div>
    </div>
  );
}

function PollPageInner() {
  return (
    <RoomProvider
      id={ROOM_ID}
      initialStorage={() => ({
        poll: new LiveObject({
          question: "",
          options: new LiveList<LiveObject<{ id: string; label: string }>>(),
        }),
        votes: new LiveMap<string, string>(),
      })}
    >
      <ClientSideSuspense
        fallback={
          <div style={{ padding: 24, fontFamily: "system-ui" }}>
            Loading poll...
          </div>
        }
      >
        {() => <PollInner />}
      </ClientSideSuspense>
    </RoomProvider>
  );
}

export default function PollPage() {
  return (
    <LiveblocksProvider authEndpoint="/api/liveblocks-auth">
      <PollPageInner />
    </LiveblocksProvider>
  );
}

